import { useState, useEffect } from "react";

/**
 * Global Clock for Camera Mock Frames
 */
export function useCameraMockSync(fps = 2) {
  const [frameIndex, setFrameIndex] = useState(0);

  useEffect(() => {
    const interval = setInterval(() => {
      setFrameIndex(prev => (prev + 1) % 1000); 
    }, 1000 / fps);

    return () => clearInterval(interval);
  }, [fps]);

  return frameIndex;
}

/**
 * Gets the Mock URL for a Specific Camera
 * Simplified: Uses /{folder}/{1..n}.jpg
 */
export function getCameraImgUrl(cameraId: number, frameIndex: number) {
  const channelId = (cameraId % 4) + 1;
  const counts = [200, 100, 200, 100]; // Image count per folder
  const currentCount = counts[channelId - 1];
  
  // Sequential frame index (1-based)
  const localIndex = (frameIndex % currentCount) + 1;
  const fileName = `${localIndex}.jpg`;

  try {
    // Correct relative path from src/platforms/m-safety/pages/dashboard/hooks/
    // to src/platforms/m-safety/mockup/imgMock/
    return new URL(
      `../../../mockup/imgMock/${channelId}/${fileName}`, 
      import.meta.url
    ).href;
  } catch (e) {
    console.warn("Failed to resolve camera mock asset:", channelId, fileName);
    return "";
  }
}
