import React, { useRef } from "react";
import { theme, Button } from "antd";
import { LeftOutlined, RightOutlined } from "@ant-design/icons";
import SensorGaugeCard from "./SensorGaugeCard";
import { SensorData } from "../data/mockData";

const { useToken } = theme;

interface EnvironmentalSensorsProps {
  sensors: SensorData[];
}

export default function EnvironmentalSensors({ sensors }: EnvironmentalSensorsProps) {
  const { token } = useToken();
  const scrollRef = useRef<HTMLDivElement>(null);

  const scroll = (direction: "LEFT" | "RIGHT") => {
    if (scrollRef.current) {
      const scrollAmount = direction === "LEFT" ? -320 : 320;
      scrollRef.current.scrollBy({ left: scrollAmount, behavior: "smooth" });
    }
  };

  return (
    <div
      style={{
        position: "relative",
        background: token.colorBgContainer,
        borderTop: `1px solid ${token.colorBorderSecondary}`,
        height: 160,
        width: "100%",
        display: "flex",
        alignItems: "center",
      }}
    >
      {/* Navigation Buttons */}
      <Button
        icon={<LeftOutlined />}
        shape="circle"
        size="small"
        onClick={() => scroll("LEFT")}
        style={{
          position: "absolute",
          left: 4,
          zIndex: 10,
          background: `${token.colorBgContainer}CC`,
          border: `1px solid ${token.colorBorder}`,
          boxShadow: token.boxShadowTertiary,
        }}
      />

      <div
        ref={scrollRef}
        style={{
          display: "flex",
          gap: 12,
          padding: "16px 36px",
          overflowX: "hidden", // Hide actual scrollbar for carousel feel
          scrollBehavior: "smooth",
          width: "100%",
        }}
      >
        {sensors.map((sensor) => (
          <div key={sensor.id} style={{ minWidth: 160, flexShrink: 0 }}>
            <SensorGaugeCard
              name={sensor.name}
              value={sensor.value}
              unit={sensor.unit}
            />
          </div>
        ))}
      </div>

      <Button
        icon={<RightOutlined />}
        shape="circle"
        size="small"
        onClick={() => scroll("RIGHT")}
        style={{
          position: "absolute",
          right: 4,
          zIndex: 10,
          background: `${token.colorBgContainer}CC`,
          border: `1px solid ${token.colorBorder}`,
          boxShadow: token.boxShadowTertiary,
        }}
      />
    </div>
  );
}
