import React, { useMemo, useState, useEffect } from "react";
import { theme, Typography, Button, Tooltip, Select, Radio } from "antd";
import {
  AppstoreOutlined,
  EnvironmentOutlined,
  BarChartOutlined,
  ExpandOutlined,
  FullscreenExitOutlined,
  DatabaseOutlined,
  VideoCameraOutlined,
} from "@ant-design/icons";
import { CameraInfo, PLANTS } from "../data/mockData";
import { useI18n } from "@/framework/i18n/hooks";
import { Dropdown, Menu } from "antd";

const { Title } = Typography;
const { useToken } = theme;

type ViewMode = "GRID" | "MAP" | "CHART";

interface DashboardHeaderProps {
  viewMode: ViewMode;
  onViewChange: (mode: ViewMode) => void;
  isFullscreen: boolean;
  onToggleFullscreen: () => void;
  selectedPlantId: number;
  onPlantChange: (id: number) => void;
  layoutCount: number;
  onLayoutChange: (count: number) => void;
  startIndex: number;
  onStartIndexChange: (index: number) => void;
  cameras: CameraInfo[];
}

export default function DashboardHeader({
  viewMode,
  onViewChange,
  isFullscreen,
  onToggleFullscreen,
  selectedPlantId,
  onPlantChange,
  layoutCount,
  onLayoutChange,
  startIndex,
  onStartIndexChange,
  cameras,
}: DashboardHeaderProps) {
  const { token } = useToken();
  const { t } = useI18n(["dashboard"]);
  const [isCompact, setIsCompact] = useState(false);

  useEffect(() => {
    const onResize = () => setIsCompact(window.innerWidth <= 600);
    window.addEventListener("resize", onResize);
    onResize();
    return () => window.removeEventListener("resize", onResize);
  }, []);

  const cameraOptions = useMemo(() => {
    const total = cameras.length;
    const options = [];
    if (layoutCount === 1) {
      for (let i = 0; i < total; i++) {
        options.push({ value: i, label: `${cameras[i].name}` });
      }
    } else {
      for (let i = 0; i < total; i += layoutCount) {
        const end = Math.min(i + layoutCount, total);
        options.push({
          value: i,
          label: `${t("header.channel")} ${i + 1} - ${end}`,
        });
      }
    }
    return options;
  }, [cameras, layoutCount, t]);

  const splitOptions = [1, 4, 9, 16];
  const splitMenu = (
    <Menu
      onClick={({ key }) => onLayoutChange(Number(key))}
      selectedKeys={[String(layoutCount)]}
      items={splitOptions.map((v) => ({ key: String(v), label: v }))}
    />
  );

  return (
    <div
      style={{
        height: 48,
        background: token.colorBgContainer,
        borderBottom: `1px solid ${token.colorBorderSecondary}`,
        display: "flex",
        alignItems: "center",
        justifyContent: "space-between",
        padding: "0 16px",
        zIndex: 1000,
      }}
    >
      <div style={{ display: "flex", alignItems: "center", gap: 16 }}>
        {isFullscreen && (
          <>
            <Title
              level={4}
              style={{ margin: 0, fontSize: 18, color: token.colorPrimary }}
            >
              M-Safety
            </Title>
            <div
              style={{
                height: 16,
                width: 1,
                background: token.colorBorderSecondary,
              }}
            />
          </>
        )}

        {isCompact ? (
          <Dropdown
            trigger={["click"]}
            placement="bottomLeft"
            menu={{
              onClick: ({ key }) => onPlantChange(Number(key)),
              selectedKeys: [String(selectedPlantId)],
              items: [
                { key: String(0), label: t("header.plant_all") },
                ...PLANTS.map((p) => ({ key: String(p.id), label: p.name })),
              ],
            }}
          >
            <Button size="small" icon={<DatabaseOutlined />} />
          </Dropdown>
        ) : (
          <Select
            value={selectedPlantId}
            onChange={onPlantChange}
            style={{ width: 160 }}
            variant="borderless"
            styles={{ popup: { root: { borderRadius: 8 } } }}
            options={[
              { label: t("header.plant_all"), value: 0 },
              ...PLANTS.map((p) => ({ label: p.name, value: p.id })),
            ]}
            suffixIcon={
              <DatabaseOutlined style={{ color: token.colorPrimary }} />
            }
            className="plant-selector"
          />
        )}
      </div>

      <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
        {viewMode === "GRID" && (
          <div
            style={{
              display: "flex",
              alignItems: "center",
              gap: 12,
              marginRight: 12,
            }}
          >
            {/* 화면분할(분할) 텍스트 제거, 오직 selector만 표시 */}
            {isCompact ? (
              <Dropdown
                menu={{
                  items: splitOptions.map((v) => ({
                    key: String(v),
                    label: v,
                  })),
                  onClick: ({ key }) => onLayoutChange(Number(key)),
                  selectedKeys: [String(layoutCount)],
                }}
                trigger={["click"]}
                placement="bottom"
              >
                <Button
                  size="small"
                  type="primary"
                  style={{ minWidth: 36, fontWeight: 700 }}
                >
                  {layoutCount}
                </Button>
              </Dropdown>
            ) : (
              <Radio.Group
                value={layoutCount}
                onChange={(e) => onLayoutChange(e.target.value)}
                size="small"
                buttonStyle="solid"
              >
                <Radio.Button value={1}>1</Radio.Button>
                <Radio.Button value={4}>4</Radio.Button>
                <Radio.Button value={9}>9</Radio.Button>
                <Radio.Button value={16}>16</Radio.Button>
              </Radio.Group>
            )}
            <div
              style={{
                height: 14,
                width: 1,
                background: token.colorBorderSecondary,
              }}
            />
            {isCompact ? (
              <Tooltip
                title={
                  cameraOptions.find((o) => o.value === startIndex)?.label || ""
                }
              >
                <Dropdown
                  trigger={["click"]}
                  placement="bottomLeft"
                  menu={{
                    onClick: ({ key }) => onStartIndexChange(Number(key)),
                    selectedKeys: [String(startIndex)],
                    items: cameraOptions.map((o) => ({
                      key: String(o.value),
                      label: o.label,
                    })),
                  }}
                >
                  <Button
                    size="small"
                    icon={<VideoCameraOutlined />}
                    aria-label={
                      cameraOptions.find((o) => o.value === startIndex)
                        ?.label || "채널"
                    }
                  />
                </Dropdown>
              </Tooltip>
            ) : (
              <Select
                value={startIndex}
                onChange={onStartIndexChange}
                size="small"
                style={{ minWidth: 120 }}
                options={cameraOptions}
                suffixIcon={<VideoCameraOutlined />}
              />
            )}
          </div>
        )}

        <div
          style={{
            display: "flex",
            background: token.colorFillAlter,
            padding: 2,
            borderRadius: 8,
          }}
        >
          <Tooltip title={t("header.view_grid")}>
            <Button
              type={viewMode === "GRID" ? "primary" : "text"}
              icon={<AppstoreOutlined />}
              onClick={() => onViewChange("GRID")}
              size="small"
              style={{ borderRadius: 6 }}
            />
          </Tooltip>
          <Tooltip title={t("header.view_map")}>
            <Button
              type={viewMode === "MAP" ? "primary" : "text"}
              icon={<EnvironmentOutlined />}
              onClick={() => onViewChange("MAP")}
              size="small"
              style={{ borderRadius: 6 }}
            />
          </Tooltip>
          <Tooltip title={t("header.view_chart")}>
            <Button
              type={viewMode === "CHART" ? "primary" : "text"}
              icon={<BarChartOutlined />}
              onClick={() => onViewChange("CHART")}
              size="small"
              style={{ borderRadius: 6 }}
            />
          </Tooltip>
        </div>

        <div
          style={{
            height: 14,
            width: 1,
            background: token.colorBorderSecondary,
            margin: "0 4px",
          }}
        />

        <Tooltip
          title={isFullscreen ? t("header.fs_exit") : t("header.fs_enter")}
        >
          <Button
            type="text"
            icon={
              isFullscreen ? <FullscreenExitOutlined /> : <ExpandOutlined />
            }
            onClick={onToggleFullscreen}
            size="small"
          />
        </Tooltip>
      </div>

      <style>{`.plant-selector .ant-select-selection-item { font-weight: 700 !important; color: ${token.colorText} !important; }`}</style>
      <style>{`
        @media (max-width: 900px) {
          .dashboard-header-root {
            flex-direction: column !important;
            align-items: stretch !important;
            height: auto !important;
            gap: 8px !important;
          }
          .dashboard-header-row {
            flex-wrap: wrap !important;
            gap: 8px !important;
          }
          .dashboard-header-row > * {
            margin-bottom: 6px !important;
          }
        }
        @media (max-width: 600px) {
          .dashboard-header-root {
            padding: 0 4px !important;
          }
          .dashboard-header-row > * {
            margin-bottom: 4px !important;
          }
          .plant-selector, .ant-select, .ant-radio-group {
            min-width: 80px !important;
            font-size: 12px !important;
          }
          .ant-btn {
            min-width: 28px !important;
            padding: 0 4px !important;
          }
        }
      `}</style>
    </div>
  );
}
