import React, { useState, useMemo, useEffect } from "react";
import { theme } from "antd";
import { getActivePlatform } from "@/framework/platforms/platformRegistry";
import { useLayout } from "@/framework/layouts/LayoutProvider";
import { useI18n } from "@/framework/i18n/hooks";

import DashboardHeader from "./components/DashboardHeader";
import CameraGrid from "./components/CameraGrid";
import MapView from "./components/MapView";
import EventTimeline from "./components/EventTimeline";
import EnvironmentalSensors from "./components/EnvironmentalSensors";
import SensorChartView from "./components/SensorChartView";

import {
  mockCameras,
  mockSensors,
  mockEvents,
  EventInfo,
} from "./data/mockData";
import { useCameraMockSync } from "./hooks/useCameraMock";

// Direct Import for I18n Force Injection
import dashboardKo from "../../locales/ko/dashboard.json";
import dashboardEn from "../../locales/en/dashboard.json";

const { useToken } = theme;

export default function Dashboard() {
  const { setLayout } = useLayout();
  const { token } = useToken();
  const { i18n } = useI18n(["dashboard"]);
  const globalFrame = useCameraMockSync(2);

  // State
  const [selectedPlantId, setSelectedPlantId] = useState(1);
  const [layoutCount, setLayoutCount] = useState(4);
  const [prevLayoutCount, setPrevLayoutCount] = useState(4);
  const [cameraStartIndex, setCameraStartIndex] = useState(0);
  const [viewMode, setViewMode] = useState<"GRID" | "MAP" | "CHART">("GRID");
  const [isFullScreen, setIsFullScreen] = useState(false);
  const [eventsVersion, setEventsVersion] = useState(0);

  // Load namespace & Force Resource Injection
  useEffect(() => {
    // Manually register bundles to solve load delay issues
    i18n.addResourceBundle("ko", "dashboard", dashboardKo, true, true);
    i18n.addResourceBundle("en", "dashboard", dashboardEn, true, true);

    const plat = getActivePlatform();
    if (plat?.layoutKey) {
      setLayout(plat.layoutKey);
    }
  }, [i18n, setLayout]);

  // Filtering logic
  const filteredCameras = useMemo(() => {
    if (selectedPlantId === 0) return mockCameras;
    return mockCameras.filter((c) => c.plantId === selectedPlantId);
  }, [selectedPlantId]);

  const filteredSensors = useMemo(() => {
    if (selectedPlantId === 0) return mockSensors;
    return mockSensors.filter((s) => s.plantId === selectedPlantId);
  }, [selectedPlantId]);

  const liveSensors = useMemo(() => {
    return filteredSensors.map((s) => {
      const fluctuation = Math.sin(globalFrame / 5 + s.id) * (s.value * 0.05);
      const noise = Math.sin(globalFrame + s.id * 1.5) * 0.2;
      return { ...s, value: s.value + fluctuation + noise };
    });
  }, [filteredSensors, globalFrame]);

  const filteredEvents = useMemo(() => {
    if (selectedPlantId === 0) return mockEvents;
    return mockEvents.filter((e) => e.plantId === selectedPlantId);
  }, [selectedPlantId, eventsVersion]);

  const handlePlantChange = (id: number) => {
    setSelectedPlantId(id);
    setCameraStartIndex(0);
  };

  const handleCameraDoubleClick = (index: number) => {
    if (layoutCount > 1) {
      setPrevLayoutCount(layoutCount);
      setLayoutCount(1);
      setCameraStartIndex(index);
    } else {
      // If currently single-view, only restore previous split when double-clicking
      // the same camera that is currently shown. Otherwise switch single view to
      // the newly double-clicked camera.
      if (index === cameraStartIndex) {
        setLayoutCount(prevLayoutCount);
      } else {
        setCameraStartIndex(index);
      }
    }
  };

  const renderMainContent = () => {
    switch (viewMode) {
      case "GRID":
        return (
          <CameraGrid
            cameras={filteredCameras}
            layoutCount={layoutCount}
            startIndex={cameraStartIndex}
            onDoubleClickCamera={handleCameraDoubleClick}
          />
        );
      case "MAP":
        return (
          <MapView
            cameras={filteredCameras}
            selectedPlantId={selectedPlantId}
          />
        );
      case "CHART":
        return <SensorChartView sensors={filteredSensors} />;
      default:
        return null;
    }
  };

  return (
    <div
      className="dashboard-root"
      style={{
        height: "100%",
        display: "flex",
        flexDirection: "column",
        background: token.colorBgLayout,
        overflow: "hidden",
      }}
    >
      <DashboardHeader
        viewMode={viewMode}
        onViewChange={setViewMode}
        isFullscreen={isFullScreen}
        onToggleFullscreen={() => setIsFullScreen(!isFullScreen)}
        selectedPlantId={selectedPlantId}
        onPlantChange={handlePlantChange}
        layoutCount={layoutCount}
        onLayoutChange={setLayoutCount}
        startIndex={cameraStartIndex}
        onStartIndexChange={setCameraStartIndex}
        cameras={filteredCameras}
      />
      <div
        className="dashboard-main"
        style={{
          flex: 1,
          display: "flex",
          flexDirection: "row",
          overflow: "hidden",
          padding: isFullScreen ? 0 : 12,
          gap: isFullScreen ? 0 : 12,
          minWidth: 0,
        }}
      >
        <div
          className="dashboard-content"
          style={{
            flex: 1,
            display: "flex",
            flexDirection: "column",
            gap: isFullScreen ? 0 : 12,
            minWidth: 0,
          }}
        >
          <div
            className="dashboard-camera-area"
            style={{
              flex: 1,
              position: "relative",
              background: "#000",
              borderRadius: isFullScreen ? 0 : token.borderRadiusLG,
              overflow: "hidden",
              border: isFullScreen
                ? "none"
                : `1px solid ${token.colorBorderSecondary}`,
              minWidth: 0,
            }}
          >
            {renderMainContent()}
          </div>
          {!isFullScreen && viewMode !== "CHART" && (
            <div className="dashboard-sensor-area" style={{ minWidth: 0 }}>
              <EnvironmentalSensors sensors={liveSensors} />
            </div>
          )}
        </div>
        {/* 반응형: 작은 화면에서는 EventTimeline이 아래로 이동 */}
        {!isFullScreen && (
          <div
            className="dashboard-timeline"
            style={{
              width: 380,
              display: "flex",
              flexDirection: "column",
              gap: 12,
              flexShrink: 0,
              minHeight: 0,
              overflow: "hidden",
              /* Desktop: fill available height; mobile will override via media query */
              height: "100%",
            }}
          >
            <div
              className="dashboard-timeline-area"
              style={{
                flex: 1,
                display: "flex",
                flexDirection: "column",
                minHeight: 0,
                height: "100%",
                overflow: "hidden",
                borderRadius: token.borderRadiusLG,
                border: `1px solid ${token.colorBorderSecondary}`,
                background: token.colorBgContainer,
              }}
            >
              <EventTimeline
                events={filteredEvents}
                onEventSelect={(ev: EventInfo) => {
                  // If event links to a camera, switch to that plant and focus the camera
                  if (ev.cameraId) {
                    const plantCamList = mockCameras.filter(
                      (c) => c.plantId === ev.plantId,
                    );
                    const idx = plantCamList.findIndex(
                      (c) => c.id === ev.cameraId,
                    );
                    setSelectedPlantId(ev.plantId);
                    setPrevLayoutCount(layoutCount);
                    setLayoutCount(1);
                    setCameraStartIndex(idx >= 0 ? idx : 0);
                  } else {
                    // no linked camera: just focus plant
                    setSelectedPlantId(ev.plantId);
                  }
                }}
                onRefresh={() => setEventsVersion((v) => v + 1)}
              />
            </div>
          </div>
        )}
      </div>
      {/* 반응형 스타일 추가 */}
      <style>{`
        @media (max-width: 900px) {
          .dashboard-main {
            flex-direction: column !important;
            gap: 8px !important;
          }
          .dashboard-timeline {
            width: 100% !important;
            flex-direction: row !important;
            /* When timeline moves below (column layout), let its height be auto and constrain via child area */
            height: auto !important;
            max-height: none !important;
            margin-top: 8px;
            gap: 0 !important;
          }
          .dashboard-content {
            flex: none !important;
            display: flex !important;
            flex-direction: column !important;
            height: 60vh !important;
            min-height: 320px;
          }
          .dashboard-camera-area {
            flex: 5 1 0% !important;
            min-height: 0;
          }
          .dashboard-sensor-area {
            flex: 3 1 0% !important;
            min-height: 0;
          }
          .dashboard-timeline-area {
            flex: 2 1 0% !important;
            min-height: 0;
            max-height: 40vh !important;
            overflow: auto !important;
          }
        }
        @media (max-width: 600px) {
          .dashboard-main {
            padding: 4px !important;
            gap: 4px !important;
          }
          .dashboard-content > div {
            border-radius: 4px !important;
          }
          .dashboard-timeline {
            margin-top: 4px;
          }
        }
      `}</style>
    </div>
  );
}
